EntityListener = {}

function EntityListener:init()
    Listener.registerCallBack(ClickToBlockEvent, self.onClickToBlock)
    Listener.registerCallBack(AttackActorNpcEvent, self.AttackActorNpc)
    Listener.registerCallBack(CreatureAttackCreatureEvent, self.onCreatureAttackCreature)

    Listener.registerCallBack(SetProcessIdEvent, self.setProcessId)
    Listener.registerCallBack(SetCanPlaceBlockIdEvent, self.setCanPlaceBlockId)

    Listener.registerCallBack(MonsterCreateEvent, self.onMonsterCreate)
    Listener.registerCallBack(MonsterDeadEvent, self.onMonsterDead)
    Listener.registerCallBack(TowerCreateEvent, self.onTowerCreate)
    Listener.registerCallBack(TowerDeadEvent, self.onTowerDead)

    Listener.registerCallBack(CreateBoxEvent, self.onCreateBox)

    Listener.registerCallBack(TowerAttackEvent, self.onTowerAttack)
    Listener.registerCallBack(TowerEjectionsEvent, self.onTowerEjections)
    Listener.registerCallBack(SynHpEvent, self.onSynHp)

end

function EntityListener.onClickToBlock(pos, face, activated)
    local grid = BaseGridListManager:getGridByPosition(pos, GamePlayer:Instance().processId)
    if grid and grid.tower then
        ClickSelfTowerEvent:invoke(grid.tower)
    end

    GamePlayer:Instance():tryPlaceTower(pos)
end

function EntityListener.AttackActorNpc(entityId)
    local tower = LuaEntityManager:getTower(entityId)
    if tower ~= nil then
        ClickSelfTowerEvent:invoke(tower)
    end

    return false
end

function EntityListener.onCreatureAttackCreature(_, _, bulletId, _)
    local bullet = BaseBullet.getBullet(bulletId)
    if bullet then
        bullet:attack()
    else
        print("can not find bullet", bulletId)
    end
end

function EntityListener.setProcessId(data)
    GamePlayer:Instance():setProcessId(data)
end

function EntityListener.setCanPlaceBlockId(data)
    GamePlayer:Instance():setCanPlaceBlockId(data)
end

function EntityListener.onMonsterCreate(data)
    local table = json.decode(data)
    GameMonster.new(table.Id, table.configId, table.pathId, table.processId)
end

function EntityListener.onMonsterDead(serverId)
    local clientId = LuaEntityManager:getClientId(serverId)
    local monster = LuaEntityManager:getMonster(clientId or 0)
    if monster then
        monster:synHp(0)
    end
end

function EntityListener.onTowerCreate(data)
    local builder = DataBuilder.new():fromData(data)
    GameTower.new(builder:getParam("Id"), builder:getVector3Param("pos"), builder:getParam("configId"), builder:getParam("userId"), builder:getParam("seed"))
end

function EntityListener.onTowerDead(serverId)
    local clientId = LuaEntityManager:getClientId(serverId)
    local tower = LuaEntityManager:getTower(clientId or 0)
    if tower then
        tower:onDie()
    end
end

function EntityListener.onCreateBox(builder)
    local placePos = builder:getVector3Param("pos")
    local yaw = builder:getParam("yaw")
    local userId = builder:getParam("userId")
    local entityId = EngineWorld:addActorNpc(placePos, yaw + 90 or 0, "g1056_jinglingqiu.actor", function(entity)
        entity:setSkillName("open")
        entity:setCanCollided(false)
    end)
    SoundUtil.playSound3D(901, placePos.x, placePos.y, placePos.z)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player or not player.Player then
        return
    end
    player.Player:getInventory():removeItem(2801, 1, 0)
    player.Player.m_holdItemActor = ""
    player.Player.m_holdItemChanged = true
    LuaTimer:schedule(function(entityId)
        player.Player.m_holdItemActor = "g1056_jinglingqiu.mesh"
        player.Player.m_holdItemChanged = true
        if player.Player:getInventory():getItemNum(2801) == 0 then
            player.Player:getInventory():addItemToInventory(Item.getItemById(2801), 0)
        end
        EngineWorld:removeEntity(entityId)
    end, 1150, nil, entityId)
end

function EntityListener.onTowerAttack(data)
    local towerId = data:getParam("towerId")
    local tower = LuaEntityManager:getTower(LuaEntityManager:getClientId(towerId))
    if tower then
        local targetIds = StringUtil.split(data:getParam("targetIds"), ",")
        tower:synAttack(targetIds)
    end
end

function EntityListener.onTowerEjections(data)
    local towerId = data:getParam("towerId")
    local targetId = data:getParam("targetId")
    local preTargetId = data:getParam("preTargetId")
    local tower = LuaEntityManager:getTower(LuaEntityManager:getClientId(towerId))
    local target = LuaEntityManager:getMonster(LuaEntityManager:getClientId(targetId))
    local preTarget = LuaEntityManager:getMonster(LuaEntityManager:getClientId(preTargetId))
    if tower and target and preTarget then
        tower:synEjections(target, preTarget)
    end
end

function EntityListener.onSynHp(data)
    local monsterId = data:getParam("monsterId")
    local hp = data:getParam("hp")
    local monster = LuaEntityManager:getMonster(LuaEntityManager:getClientId(monsterId))
    if monster then
        monster:synHp(tonumber(hp))
    end
end